@startuml
!theme plain

class "JuniorExperienceManager" as JuniorExperienceManager {
}

class "PrimaryExperienceManager" as PrimaryExperienceManager {
}

class "SeniorExperienceManager" as SeniorExperienceManager {
}

class "AbstractExprienceManager" as AbstractExprienceManager {
  <<abstract>>
  next:LevelManager
}

class "LevelManager" as LevelManager {
  <<interface>>
  handleExprience():void
  forName():String
}

JuniorExperienceManager --|> AbstractExprienceManager
PrimaryExperienceManager --|> AbstractExprienceManager
SeniorExperienceManager --|> AbstractExprienceManager

AbstractExprienceManager ..> LevelManager
@enduml
